206:   /**
207:    * Calculate cost estimation based on project type and features
208:    */
209:   async estimateCosts(
210:     projectType: string,
211:     features: string[],
212:     complexity: 'low' | 'medium' | 'high' = 'medium'
213:   ): Promise<CostEstimate[]> {
214:     const services = serviceDatabase[projectType as keyof typeof serviceDatabase] || serviceDatabase.web;
215:     const complexityFactors = { low: 0.8, medium: 1.0, high: 1.5 };
216:     const factor = complexityFactors[complexity];
217: 
218:     const estimates: CostEstimate[] = [];
219: 
220:     // Select relevant services based on features and project type
221:     const selectedServices = this.selectRelevantServices(projectType, features);
222: 
223:     for (const service of selectedServices) {
224:       const serviceData = services[service as keyof typeof services];
225:       if (serviceData) {
226:         const baseCost = (serviceData as any).base;
227:         const quantity = this.estimateQuantity(service, projectType);
228:         const totalCost = baseCost * quantity * factor;
229: 
230:         estimates.push({
231:           service,
232:           baseCost,
233:           quantity,
234:           complexityFactor: factor,
235:           totalCost: Math.round(totalCost),
236:         });
237:       }
238:     }
239: 
240:     return estimates;
241:   }
